VALUES
  ('dietitian-moex-06914', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者是嬰兒副食品選用的建議事項？ 給予新的副食品時，一次以一種為原則 開始吃副食品時，應停止哺餵母乳以免熱量過剩 大便中如出現未消化的食物如蔬菜的纖維等，應立即停止餵食 開始餵食糊狀食物（如米糊、果泥等）時，最好將食物加入奶瓶內一起餵食', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06915', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '11歲男孩的身體質量指數正常範圍是14.8～20.7，若身高為140公分的該年齡男孩，下列那一個體重 （公斤）不在正常範圍內？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06916', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '30  35  40', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06917', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '自102年起，負責學校午餐的中央權責單位為： 行政院農業委員會    衛生福利部食品藥物管理署 教育部體育署    教育部國民及學前教育署', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06918', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某牌豆漿每瓶熱量300大卡、鈉含量200毫克、添加糖所提供的熱量占總熱量的25%，此豆漿是否符合 「校園飲品及點心販售範圍」之規定？ 符合規定 不符合規定，熱量含量太高，鈉含量及糖所提供的熱量占總熱量的比例合規定 不符合規定，熱量含量及添加糖所提供的熱量占總熱量比例均太高，鈉含量合規定 不符合規定，熱量含量、鈉含量及添加糖所提供的熱量占總熱量比例都太高', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06919', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於營養諮詢的訊息提供（information giving）原則，下列敘述何者錯誤？ 儘量避免提供負面訊息 每次給予的新資訊不要太多 應詢問病患對於此些訊息的感覺或想法 病患對於諮詢過程中較早提供的資訊會記憶較久的時間', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06920', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '臺灣地區食品營養成分資料庫中提供下列那一項營養素的資料？ 鋅  硒  葉酸  維生素K', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06921', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據市售包裝食品營養宣稱規範，可補充攝取之營養宣稱，不包括下列何者？ 鈣  寡醣  維生素C  膳食纖維', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06922', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於可宣稱全穀產品之原則，下列敘述何者錯誤？ 全穀重量百分比指扣除原料中水分後之重量 穀物經過破碎，取其胚芽或麩皮，不摻其他成分，得稱為全穀類 固體產品所含全穀成分占配方總重量百分比51%（含）以上，始可以全穀產品宣稱 產品所含全穀成分未達配方總重量百分比51%（含）以上，可標示「本產品部分原料使用全穀粉（如： 全麥）原料製作」', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06923', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '當尿中甲基丙二酸（methylmalonic acid; MMA）排泄量增加時，表示體內何種營養素缺乏？ 維生素B  維生素B  維生素B   菸鹼酸', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
